import { mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, resolve } from 'node:path';
import { readFileSync } from 'node:fs';

import { describe, expect, it } from 'vitest';

import {
  createHfBpeMetaspaceTokenizer,
  loadHfBpeMetaspaceTokenizerFromFile,
} from '../src/hf-tokenizer-json';

type Fixture = {
  model: {
    type: 'BPE';
    unk_token: string;
    byte_fallback: boolean;
    vocab: Record<string, number>;
    merges: string[];
  };
  pre_tokenizer: {
    type: 'Metaspace';
    replacement: string;
    prepend_scheme: 'first';
    split: false;
  };
  added_tokens: Array<{
    id: number;
    content: string;
    special: boolean;
  }>;
};

function addTokenChain(
  vocab: Record<string, number>,
  merges: string[],
  token: string,
  finalId: number,
): void {
  const chars = Array.from(token);
  for (const char of chars) {
    if (vocab[char] === undefined) vocab[char] = Object.keys(vocab).length + 100;
  }
  let left = chars[0]!;
  for (const right of chars.slice(1)) {
    const merged = left + right;
    merges.push(`${left} ${right}`);
    if (vocab[merged] === undefined) vocab[merged] = Object.keys(vocab).length + 100;
    left = merged;
  }
  vocab[token] = finalId;
}

function mistralV3ParisFixture(): Fixture {
  const vocab: Record<string, number> = {
    '<unk>': 0,
    '<s>': 1,
    '</s>': 2,
    '[INST]': 3,
    '[/INST]': 4,
    'the': 1040,
    '▁Paris': 6233,
  };
  const merges: string[] = [];
  addTokenChain(vocab, merges, '▁The', 1183);
  addTokenChain(vocab, merges, '▁capital', 6333);
  addTokenChain(vocab, merges, '▁of', 1070);
  addTokenChain(vocab, merges, '▁France', 5611);
  addTokenChain(vocab, merges, '▁is', 1117);
  vocab['▁'] = 29473;

  return {
    model: {
      type: 'BPE',
      unk_token: '<unk>',
      byte_fallback: true,
      vocab,
      merges,
    },
    pre_tokenizer: {
      type: 'Metaspace',
      replacement: '▁',
      prepend_scheme: 'first',
      split: false,
    },
    added_tokens: [
      { id: 0, content: '<unk>', special: true },
      { id: 1, content: '<s>', special: true },
      { id: 2, content: '</s>', special: true },
      { id: 3, content: '[INST]', special: true },
      { id: 4, content: '[/INST]', special: true },
    ],
  };
}

describe('HF BPE Metaspace tokenizer JSON', () => {
  it('matches the Mistral v3 Paris qspec token contract', () => {
    const tokenizer = createHfBpeMetaspaceTokenizer(
      JSON.stringify(mistralV3ParisFixture()),
    );

    expect(tokenizer.encode('The capital of France is')).toEqual([
      1183,
      6333,
      1070,
      5611,
      1117,
    ]);
    expect(
      tokenizer.encode('[INST] The capital of France is [/INST]', {
        addBos: true,
      }),
    ).toEqual([1, 3, 1183, 6333, 1070, 5611, 1117, 29473, 4]);
    expect(tokenizer.decode([6233])).toBe('Paris');
    expect(tokenizer.decode([1040])).toBe('the');
  });

  it('loads tokenizer JSON from disk for production configuration', () => {
    const dir = mkdtempSync(join(tmpdir(), 'hf-tokenizer-json-'));
    try {
      const path = join(dir, 'tokenizer.json');
      writeFileSync(path, JSON.stringify(mistralV3ParisFixture()));
      const tokenizer = loadHfBpeMetaspaceTokenizerFromFile(path);
      expect(tokenizer.encode('The capital of France is')).toEqual([
        1183,
        6333,
        1070,
        5611,
        1117,
      ]);
    } finally {
      rmSync(dir, { recursive: true, force: true });
    }
  });
});

describe('Mistral serving qspec metadata', () => {
  it('declares the serving tokenizer/template needed for production readiness', () => {
    const qspec = JSON.parse(
      readFileSync(
        resolve(__dirname, '../../monster-swarm/qspecs/mistral-7b.qspec.json'),
        'utf8',
      ),
    ) as Record<string, unknown>;

    expect(qspec['prompt']).toBe('The capital of France is');
    expect(qspec['prompt_tokens']).toEqual([1183, 6333, 1070, 5611, 1117]);
    expect(qspec['expect_token']).toBe(6233);
    expect(qspec['serving_tokenizer']).toBe('hf-bpe-metaspace');
    expect(qspec['chat_template']).toBe('mistral-v3-instruct');
  });
});
